import subprocess
import os
import re
import shlex
from google.cloud import storage


def process_image(event, context):
    """Cloud Function triggered by Cloud Storage event to convert images.
    
    Args:
        event (dict): Event payload containing bucket and file information.
        context (google.cloud.functions.Context): Metadata for the event.
    """
    bucket_name = event.get('bucket', '')
    file_name = event.get('name', '')
    metadata = event.get('metadata', {})
    
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', '')
    quality = metadata.get('quality', '')
    
    if not bucket_name or not file_name:
        print("Error: Missing bucket or file name in event.")
        return
    
    ALLOWED_FORMATS = {'png', 'jpg', 'jpeg', 'gif', 'bmp', 'tiff', 'webp'}
    ALLOWED_FILENAME_PATTERN = re.compile(r'^[a-zA-Z0-9_\-./]+$')
    ALLOWED_RESIZE_PATTERN = re.compile(r'^\d{1,5}x\d{1,5}$')
    ALLOWED_QUALITY_PATTERN = re.compile(r'^\d{1,3}$')
    ALLOWED_BUCKET_PATTERN = re.compile(r'^[a-zA-Z0-9_\-.]+$')
    
    if not ALLOWED_BUCKET_PATTERN.match(bucket_name):
        print(f"Error: Invalid bucket name: {bucket_name}")
        return
    
    if not ALLOWED_FILENAME_PATTERN.match(file_name):
        print(f"Error: Invalid file name contains disallowed characters: {file_name}")
        return
    
    if '..' in file_name or file_name.startswith('/'):
        print(f"Error: Path traversal detected in file name: {file_name}")
        return
    
    output_format = output_format.lower().strip()
    if output_format not in ALLOWED_FORMATS:
        print(f"Error: Unsupported output format: {output_format}")
        return
    
    if resize and not ALLOWED_RESIZE_PATTERN.match(resize):
        print(f"Error: Invalid resize parameter: {resize}")
        return
    
    if quality:
        if not ALLOWED_QUALITY_PATTERN.match(quality):
            print(f"Error: Invalid quality parameter: {quality}")
            return
        quality_int = int(quality)
        if quality_int < 1 or quality_int > 100:
            print(f"Error: Quality must be between 1 and 100: {quality}")
            return
    
    tmp_dir = '/tmp'
    input_path = os.path.join(tmp_dir, os.path.basename(file_name))
    
    file_base, _ = os.path.splitext(os.path.basename(file_name))
    if not ALLOWED_FILENAME_PATTERN.match(file_base):
        print(f"Error: Invalid file base name: {file_base}")
        return
    
    output_filename = f"{file_base}.{output_format}"
    output_path = os.path.join(tmp_dir, output_filename)
    
    resolved_input = os.path.realpath(input_path)
    resolved_output = os.path.realpath(output_path)
    if not resolved_input.startswith(tmp_dir) or not resolved_output.startswith(tmp_dir):
        print("Error: Path traversal detected in resolved paths.")
        return
    
    try:
        storage_client = storage.Client()
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        blob.download_to_filename(input_path)
        print(f"Downloaded {file_name} from {bucket_name} to {input_path}")
    except Exception as e:
        print(f"Error downloading file: {e}")
        return
    
    convert_cmd = ['/usr/bin/convert', input_path]
    
    if resize:
        convert_cmd.extend(['-resize', resize])
    
    if quality:
        convert_cmd.extend(['-quality', quality])
    
    convert_cmd.append(output_path)
    
    print(f"Running ImageMagick command: {convert_cmd}")
    
    try:
        result = subprocess.run(
            convert_cmd,
            timeout=120,
            capture_output=True,
            shell=False,
            env={
                'PATH': '/usr/bin',
                'MAGICK_TEMPORARY_PATH': '/tmp',
                'MAGICK_DISK_LIMIT': '256MiB',
                'MAGICK_MEMORY_LIMIT': '128MiB',
                'MAGICK_MAP_LIMIT': '64MiB',
            }
        )
        
        if result.returncode != 0:
            print(f"ImageMagick conversion failed with return code {result.returncode}")
            print(f"stderr: {result.stderr.decode('utf-8', errors='replace')}")
            return
        
        print(f"Successfully converted {file_name} to {output_format}")
    except subprocess.TimeoutExpired:
        print("Error: ImageMagick conversion timed out.")
        return
    except Exception as e:
        print(f"Error during conversion: {e}")
        return
    
    try:
        output_blob_name = f"converted/{output_filename}"
        output_blob = bucket.blob(output_blob_name)
        output_blob.upload_from_filename(output_path)
        print(f"Uploaded converted file to gs://{bucket_name}/{output_blob_name}")
    except Exception as e:
        print(f"Error uploading converted file: {e}")
    finally:
        if os.path.exists(input_path):
            os.remove(input_path)
        if os.path.exists(output_path):
            os.remove(output_path)